INSERT INTO engine_bug_queue (bug_class, title, severity, owner_cluster, root_cause, prevention_rule, probe_type, probe_logic, status, concepts_affected, fixed_in_files, discovered_in_session, row_type) VALUES
('tts_codemix_telugu_mispronounces_inline_english', 'Telugu (te-IN) stored TTS mispronounces inline Latin-script English in code-mixed narration — single letters ("V" → "we" not "vee", "E"), hyphen-joined compounds ("Equal-V"), and scattered English tokens read unnaturally', 'MAJOR', 'ambiguous', 'The multilingual stored-audio narration keeps physics/technical terms in English (Telgish, by design) and feeds that code-mixed text straight to Sarvam Bulbul te-IN. The te-IN voice does NOT reliably pronounce romanized English embedded in Telugu: standalone single capital letters are the worst ("V" comes out like "we" instead of "vee", "E" mis-stressed), hyphen-joined mixed compounds ("Equal-V points") garble, and dense English fragments ("drawn", "point") read with a wrong accent. Caught by the founder on electric_potential_meaning STATE_6 s6_4 ("V ఒక scalar, ... Equal-V points ..."). Systemic across all te-IN narration (Telugu is worse than hi-IN here). The caption text and the spoken text are currently the SAME field (text_te), so making the spoken form pronounceable also changes the displayed caption unless the two are separated.', 'For Telugu/Hindi STORED TTS, the SPOKEN text must be pronounceable by the te-IN/hi-IN voice: (1) transliterate standalone single Latin letters + symbol-names to target-script phonetics (V→వీ / वी, E→ఈ / ई, q→క్యూ / क्यू, W→డబ్ల్యూ); (2) avoid hyphen-joined English compounds — reword (e.g. "Equal-V points" → "ఒకే V విలువ ఉన్న points" / a natural phrase); (3) prefer a SEPARATE spoken-text field from the English-term caption so readability and pronunciation are both satisfied; (4) ALWAYS founder/native-listen a per-language sample before bulk generation, and consider bulbul:v3 voices. RESOLVED 2026-06-28: the real fix was (a) bulbul:v3 / priya (NOT transliteration — Sarvam docs state transliteration REDUCES quality; v3 is built for code-mixing / Romanized text / abbreviations and pronounces inline English natively), and (b) expanding bare single-letter symbols to full names in the SPOKEN narration (E→electric field E, V→potential V, B→magnetic field B, I→current I, F→force F, ...) for clarity + unambiguous pronunciation — applied across all 27 field_3d diamonds, all 3 langs. Approach (1) above (transliterate to target script) is SUPERSEDED for v3. New rule candidate (Rule 30) for CLAUDE.md.', 'manual', 'Listen to a Telugu state containing single letters/symbols (e.g. electric_potential_meaning STATE_6 "V ఒక scalar"): every English letter/term must be pronounced correctly (V = "vee", not "we"), no garbled hyphen compounds. A/B candidate clips live at review-site/_tts_candidates/ (A=current, B=transliterated-fix, C/D=bulbul:v3).', 'FIXED', ARRAY['electric_potential_meaning'], ARRAY['src/scripts/generate_tts_audio.ts (default model→bulbul:v3, speaker→priya; AbortSignal.timeout(30000) on fetch; 6 retries)', 'src/data/concepts/*.json (bare single-letter symbols expanded to full names in tts_sentences, all 3 langs, 27 diamonds)'], 'session_2026-06-27_tts_telugu_pronunciation', 'incident')
ON CONFLICT (bug_class) DO NOTHING;
